cat > /tmp/test_import.go << 'EOF'
package main

import (
	"context"
	"go.flipt.io/flipt/internal/storage"
	"go.flipt.io/flipt/internal/storage/sql/common"
	"go.flipt.io/flipt/internal/storage/fs"
)

func main() {
	// This is just to verify the packages can be imported
	// and that the FlagExists method exists in the interface
	_ = (*storage.ReadOnlyFlagStore)(nil)

	// These should implement ReadOnlyFlagStore
	var _ storage.ReadOnlyFlagStore = &common.Store{}
	var _ storage.ReadOnlyFlagStore = &fs.Snapshot{}
	var _ storage.ReadOnlyFlagStore = &fs.Store{}
}
EOF
go run /tmp/test_import.go 2>&1

cat > /tmp/compile_check.go << 'EOF'
package main

// This is a simple syntax check for the interface changes
// It won't actually run, but go will verify the file parses correctly

import (
	"context"
	flipt "go.flipt.io/flipt/rpc/flipt"
)

// Mock types to verify the method signatures
type ReadOnlyFlagStore interface {
	GetFlag(ctx context.Context, req interface{}) (*flipt.Flag, error)
	FlagExists(ctx context.Context, req interface{}) (bool, error)
	ListFlags(ctx context.Context, req interface{}) (interface{}, error)
	CountFlags(ctx context.Context, ns interface{}) (uint64, error)
}

type mockStore struct{}

func (m *mockStore) GetFlag(ctx context.Context, req interface{}) (*flipt.Flag, error) { return nil, nil }
func (m *mockStore) FlagExists(ctx context.Context, req interface{}) (bool, error)      { return false, nil }
func (m *mockStore) ListFlags(ctx context.Context, req interface{}) (interface{}, error) { return nil, nil }
func (m *mockStore) CountFlags(ctx context.Context, ns interface{}) (uint64, error)     { return 0, nil }

func main() {
	var _ ReadOnlyFlagStore = &mockStore{}
}
EOF
go run /tmp/compile_check.go 2>&1

cat > /tmp/verify_syntax.go << 'EOF'
package main

import (
	"fmt"
	"go/parser"
	"go/token"
	"os"
)

func main() {
	files := []string{
		"/workspace/internal/storage/storage.go",
		"/workspace/internal/storage/sql/common/flag.go",
		"/workspace/internal/storage/fs/snapshot.go",
		"/workspace/internal/storage/fs/store.go",
	}

	fset := token.NewFileSet()
	for _, file := range files {
		_, err := parser.ParseFile(fset, file, nil, parser.AllErrors)
		if err != nil {
			fmt.Printf("ERROR in %s:\n%v\n", file, err)
			os.Exit(1)
		}
		fmt.Printf("✓ %s\n", file)
	}
	fmt.Println("\nAll files have valid Go syntax!")
}
EOF
go run /tmp/verify_syntax.go

